const items = $input.all();
return items.map((item, index) => {
  const rawText = item.json.text || '';
  const fileName = item.json.fileName || 'unknown.pdf';
  // Use runIndex to offset the batch, assuming batchSize is dynamic but we just use item offset for unique ID loosely
  return {
    json: { 
      paper_text: rawText, 
      file_name: fileName,
      paper_number: ($runIndex * items.length) + index + 1 
    }
  };
});

const items = $input.all();
return items.map(item => {
  const rawOutput = item.json.output || item.json.text || '';
  let parsed;
  try {
    let cleaned = rawOutput.replace(/\`\`\`json\n?/g, '').replace(/\`\`\`\n?/g, '').trim();
    parsed = JSON.parse(cleaned);
  } catch (e) {
    const jsonMatch = rawOutput.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      try { parsed = JSON.parse(jsonMatch[0]); } catch (e2) {
        return { json: { error: 'Failed to parse', raw_output: rawOutput } };
      }
    } else {
      return { json: { error: 'No JSON found', raw_output: rawOutput } };
    }
  }

  const requiredFields = ['paper_id', 'title', 'authors'];
  const missingFields = requiredFields.filter(f => !parsed[f]);
  if (missingFields.length > 0) {
    parsed.extraction_notes = (parsed.extraction_notes || '') + ' WARNING: Missing fields';
    parsed.extraction_confidence = 'LOW';
  }

  return { json: { extracted_paper: parsed } };
});

const items = $input.all();
const extracted = [];
for (const item of items) {
  if (item.json.extracted_paper) {
    extracted.push(item.json.extracted_paper);
  }
}
return [{ json: { extracted_papers: extracted } }];

// The input is { extracted_papers: [...] } from the collect node
const data = $input.first().json;
return [{
  json: { "success": true },
  binary: {
    json_data: {
      data: Buffer.from(JSON.stringify(data, null, 2)).toString('base64'),
      mimeType: 'application/json',
      fileName: 'temp_extracted.json'
    }
  }
}];
